/**
 * Shielded Transaction Smoke Test
 *
 * Tests the full shield → stats → nullifier-check flow on live testnet.
 * Run: node --experimental-specifier-resolution=node smoke-test-shielded.mjs
 *
 * NOTE: shielded_transfer and unshield require STARK proofs generated by the
 * Rust prover. This test covers the endpoints that work without proofs.
 */

// We use raw fetch since we need the full API URL control
const BASE = "https://testnet.rougechain.io/api";

async function get(path) {
  const res = await fetch(`${BASE}${path}`);
  return res.json();
}

async function post(path, body) {
  const res = await fetch(`${BASE}${path}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  return res.json();
}

async function main() {
  console.log("=== Shielded Transaction Smoke Test ===\n");

  // 1. Check shielded stats endpoint
  console.log("1. GET /api/shielded/stats");
  const stats = await get("/shielded/stats");
  console.log("   ", JSON.stringify(stats));
  if (!stats.success) throw new Error("Stats endpoint failed");
  console.log("   ✅ Stats endpoint working\n");

  // 2. Check nullifier endpoint (random hash should return not-spent)
  const fakeNullifier = "0".repeat(64);
  console.log(`2. GET /api/shielded/nullifier/${fakeNullifier.slice(0, 16)}...`);
  const nullCheck = await get(`/shielded/nullifier/${fakeNullifier}`);
  console.log("   ", JSON.stringify(nullCheck));
  if (nullCheck.spent !== false) throw new Error("Expected nullifier to be unspent");
  console.log("   ✅ Nullifier check working\n");

  // 3. Try shield endpoint WITHOUT signing (should fail with 400 — proves route exists)
  console.log("3. POST /api/v2/shielded/shield (unsigned — expect 400)");
  const shieldResult = await post("/v2/shielded/shield", {
    payload: { amount: 100, commitment: "a".repeat(64) },
    signature: "invalid",
    public_key: "invalid",
  });
  console.log("   ", JSON.stringify(shieldResult));
  if (shieldResult.success === true) throw new Error("Unsigned tx should not succeed");
  console.log("   ✅ Shield endpoint rejects unsigned tx\n");

  // 4. Try shielded transfer endpoint (unsigned — expect 400)
  console.log("4. POST /api/v2/shielded/transfer (unsigned — expect 400)");
  const transferResult = await post("/v2/shielded/transfer", {
    payload: { nullifiers: ["a".repeat(64)], output_commitments: ["b".repeat(64)], proof: "deadbeef" },
    signature: "invalid",
    public_key: "invalid",
  });
  console.log("   ", JSON.stringify(transferResult));
  if (transferResult.success === true) throw new Error("Unsigned tx should not succeed");
  console.log("   ✅ Shielded transfer endpoint rejects unsigned tx\n");

  // 5. Try unshield endpoint (unsigned — expect 400)
  console.log("5. POST /api/v2/shielded/unshield (unsigned — expect 400)");
  const unshieldResult = await post("/v2/shielded/unshield", {
    payload: { nullifiers: ["a".repeat(64)], amount: 100, proof: "deadbeef" },
    signature: "invalid",
    public_key: "invalid",
  });
  console.log("   ", JSON.stringify(unshieldResult));
  if (unshieldResult.success === true) throw new Error("Unsigned tx should not succeed");
  console.log("   ✅ Unshield endpoint rejects unsigned tx\n");

  // Summary
  console.log("=== Results ===");
  console.log("Commitments on-chain:", stats.commitment_count);
  console.log("Nullifiers on-chain: ", stats.nullifier_count);
  console.log("Active shielded notes:", stats.active_notes);
  console.log("\n✅ All 5 endpoint checks passed!");
}

main().catch((e) => {
  console.error("\n❌ SMOKE TEST FAILED:", e.message);
  process.exit(1);
});
